const body = $input.first().json;
const requirementId = body.requirement_id || body.requirement?.id || body.requirement?.requirement_id;
if (!requirementId) throw new Error('Falta requirement_id. El backend debe enviar { requirement: { id } } o { requirement_id }.');
return [{ json: {
  requirement_id: requirementId,
  approval_id: body.approval_id || null,
  approved_by_id: body.approved_by_id || body.requirement?.approved_by_id || null,
  approved_by: body.approved_by || 'Jefe de IT',
  manager_email: body.manager_email || $env.MANAGER_EMAIL || '',
  backend_payload: body
}}];

function collect(name) {
  const raw = $items(name).map(item => item.json);
  if (raw.length === 1 && Array.isArray(raw[0])) return raw[0];
  return raw;
}
const payload = $('Normalizar Payload Backend').first().json;
const requirement = collect('Consultar Requirement')[0];
const tickets = collect('Consultar Tickets Asignados');
const managers = collect('Consultar Managers');
if (!requirement) throw new Error('Requirement no encontrado en Supabase.');
const project = requirement.projects || {};
const manager = managers.find(m => m.id === project.owner_id) || managers.find(m => m.team_id === project.team_id) || managers[0] || null;
const managerEmail = payload.manager_email || manager?.email || '';
const managerId = manager?.id || payload.approved_by_id || null;
const assigned = tickets.filter(t => t.assignee_id && t.members);
if (!assigned.length) throw new Error('No hay tickets asignados. Ejecuta /api/agents/assignment antes de aprobar o antes de llamar n8n.');
return assigned.map((ticket, index) => {
  const member = ticket.members || {};
  const currentAssignment = (ticket.ticket_assignments || []).find(a => a.is_current && a.assignee_id === ticket.assignee_id) || (ticket.ticket_assignments || [])[0] || {};
  const reasoning = ticket.assignment_reasoning || currentAssignment.reasoning || 'Asignado por el Assignment Agent del backend usando skills y carga actual.';
  return { json: {
    approval_id: payload.approval_id,
    requirement_id: requirement.id,
    requirement_title: requirement.title || 'Requirement aprobado',
    requirement_summary: requirement.summary || '',
    project_id: project.id,
    project_name: project.name || 'Proyecto',
    team_id: project.team_id,
    approved_by: payload.approved_by,
    manager_id: managerId,
    manager_email: managerEmail,
    ticket_id: ticket.id,
    ticket_title: ticket.title,
    ticket_description: ticket.description,
    priority: ticket.priority || 'medium',
    estimate_hours: ticket.estimate_hours || 0,
    required_skill: ticket.skills?.label || ticket.skills?.code || 'general',
    risk_pct: ticket.risk_pct || currentAssignment.risk_pct || 0,
    status: ticket.status,
    deadline: ticket.deadline,
    kanban_order: ticket.kanban_order || index + 1,
    assignment_reasoning: reasoning,
    assignee_id: member.id,
    assignee_name: member.name || 'Developer',
    assignee_email: member.email || '',
    assignee_role: member.role || '',
    assignee_current_load: member.current_load || 0
  }};
});

const assignments = $input.first().json.assignments || [];
if (!assignments.length) return [];
const first = assignments[0];
const rows = assignments.map(a => {
  const riskColor = a.risk_pct > 60 ? '#dc2626' : a.risk_pct > 40 ? '#d97706' : '#16a34a';
  return `<tr><td style="padding:8px 12px;border-top:1px solid #e5e5e5">${a.ticket_title}</td><td style="padding:8px 12px;border-top:1px solid #e5e5e5">${a.assignee_name}</td><td style="padding:8px 12px;border-top:1px solid #e5e5e5">${a.priority}</td><td style="padding:8px 12px;border-top:1px solid #e5e5e5;color:${riskColor};font-weight:700">${a.risk_pct}%</td><td style="padding:8px 12px;border-top:1px solid #e5e5e5">${a.assignment_reasoning}</td></tr>`;
}).join('');
const totalHours = assignments.reduce((sum, a) => sum + (a.estimate_hours || 0), 0);
const highRisk = assignments.filter(a => a.risk_pct > 60).length;
const html = `<div style="font-family:Arial,sans-serif;max-width:760px;margin:0 auto;color:#111"><h2>Asignaciones notificadas: ${first.requirement_title}</h2><p><strong>Proyecto:</strong> ${first.project_name}</p><p>El backend ejecuto el Assignment Agent, guardo las asignaciones en Supabase y n8n notifico a los developers.</p><div style="display:flex;gap:16px;margin:16px 0"><div style="background:#f5f5f5;padding:12px 18px;border-radius:8px"><strong>${assignments.length}</strong><br><span style="color:#6b7280;font-size:13px">tickets</span></div><div style="background:#f5f5f5;padding:12px 18px;border-radius:8px"><strong>${totalHours}h</strong><br><span style="color:#6b7280;font-size:13px">estimadas</span></div><div style="background:${highRisk ? '#fef2f2' : '#f0fdf4'};padding:12px 18px;border-radius:8px"><strong>${highRisk}</strong><br><span style="color:#6b7280;font-size:13px">riesgo alto</span></div></div><table style="border-collapse:collapse;width:100%"><tr style="background:#111;color:#fff"><th style="padding:8px 12px;text-align:left">Ticket</th><th style="padding:8px 12px;text-align:left">Developer</th><th style="padding:8px 12px;text-align:left">Prioridad</th><th style="padding:8px 12px;text-align:left">Riesgo</th><th style="padding:8px 12px;text-align:left">Por que</th></tr>${rows}</table><p style="font-size:13px;color:#6b7280;margin-top:24px">Fuente de decision: backend Assignment Agent + Supabase.</p></div>`;
return [{ json: { approval_id: first.approval_id, manager_id: first.manager_id, manager_email: first.manager_email, requirement_id: first.requirement_id, requirement_title: first.requirement_title, total_assignments: assignments.length, summary_html: html } }];
